def signal(lane):
 return f'''<div class="diagram"><svg viewBox="0 0 720 175" role="img" aria-label="{e(lane['title'])} signal-to-action map"><defs><marker id="arrow" markerWidth="8" markerHeight="8" refX="7" refY="4" orient="auto"><path d="M0 0L7 4 0 8Z" fill="#94a3b8"/></marker></defs><text x="16" y="24" class="label">SIGNAL MAP · {e(lane['title']).upper()}</text><rect x="15" y="55" width="190" height="72" rx="10" fill="#fff" stroke="#cbd5e1"/><text x="110" y="83" text-anchor="middle" class="label">PRIMARY SIGNAL</text><text x="110" y="105" text-anchor="middle" class="small">fresh, specific change</text><line x1="206" y1="91" x2="282" y2="91" stroke="#94a3b8" stroke-width="2" marker-end="url(#arrow)"/><rect x="284" y="55" width="190" height="72" rx="10" fill="#effdf6" stroke="#01dc82"/><text x="379" y="83" text-anchor="middle" class="label">OPERATING RULE</text><text x="379" y="105" text-anchor="middle" class="small">constrain · measure</text><line x1="475" y1="91" x2="551" y2="91" stroke="#94a3b8" stroke-width="2" marker-end="url(#arrow)"/><rect x="553" y="55" width="152" height="72" rx="10" fill="#fff" stroke="#cbd5e1"/><text x="629" y="83" text-anchor="middle" class="label">NEXT TEST</text><text x="629" y="105" text-anchor="middle" class="small">small + reversible</text><path d="M110 145H629" stroke="#cfe66a" stroke-width="5" stroke-linecap="round"/></svg></div>'''
def report(lane):
 cards=''.join(f'''<article class="item"><div class="badges"><span class="badge good">{e(s['source_type'])}</span><span class="badge">{e(s['published_or_updated'])}</span></div><h2><a href="{e(s['url'])}">{e(s['title'])}</a></h2><dl><dt>What it is</dt><dd>{e(s['what'])}</dd><dt>Why useful now</dt><dd>{e(s['why'])}</dd><dt>Buildn / client use</dt><dd>{e(s['usecase'])}</dd><dt>Caveat</dt><dd>{e(s['caveat'])}</dd></dl><p class="action"><b>Follow-up action:</b> {e(s['usefulness'])}</p></article>''' for s in lane['sources'])
 matrix=''.join(f'<tr><th>{e(s["title"].split(" — ")[0])}</th><td>●</td><td>●</td><td>●</td><td>○</td></tr>' for s in lane['sources'])
 trail=''.join(f'<li><a href="{e(s["url"])}">{e(s["title"])}</a></li>' for s in lane['sources'])
 return f'''<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Daily Ingest Dossier — {e(lane['title'])} — {DATE}</title><meta name="lib:group" content="report"><meta name="lib:date" content="{DATE}"><link rel="preconnect" href="https://fonts.googleapis.com"><link rel="preconnect" href="https://fonts.gstatic.com" crossorigin><link href="https://fonts.googleapis.com/css2?family=Newsreader:opsz,wght@6..72,400;6..72,600&family=Plus+Jakarta+Sans:wght@400;500;600;700&display=swap" rel="stylesheet"><style>:root{{--brand:#01dc82;--deep:#033330;--lime:#cfe66a;--red:#b3261e;--amber:#9a6700;--ink:#0f172a;--muted:#475569;--line:#e2e8f0;--bg:#fafaf9;--card:#fff;--serif:"Newsreader",Georgia,serif;--sans:"Plus Jakarta Sans",system-ui,sans-serif}}*{{box-sizing:border-box}}body{{margin:0;background:var(--bg);color:var(--ink);font:15px/1.58 var(--sans)}}main{{max-width:64rem;margin:auto;padding:3rem 1.4rem 4rem}}h1,h2,h3{{font-family:var(--serif);color:var(--deep);line-height:1.13}}h1{{font-size:2.3rem;margin:.6rem 0}}h2{{font-size:1.35rem;margin:.5rem 0}}h3{{font-size:1.15rem;margin:0}}a{{color:#087f51}}.wordmark{{display:flex;align-items:center;gap:.55rem;font-weight:700;color:var(--deep)}}.date,.kicker{{font:12px ui-monospace,monospace;color:var(--muted);letter-spacing:.04em}}.kicker{{color:#087f51;font-weight:700}}.lead{{font-size:1.04rem;max-width:55rem}}.card,.item{{background:var(--card);border:1px solid var(--line);border-radius:12px;padding:1.3rem;margin:1.25rem 0}}.diagram{{border:1px solid var(--line);border-radius:9px;background:#fff;padding:.8rem;margin:1rem 0}}svg{{display:block;width:100%;height:auto}}.label{{font:700 10px var(--sans);fill:#475569;letter-spacing:.09em}}.small{{font:12px var(--sans);fill:#475569}}.badges{{display:flex;gap:.45rem;flex-wrap:wrap}}.badge{{font-size:10px;letter-spacing:.06em;text-transform:uppercase;font-weight:700;background:#f1f5f9;color:#475569;padding:.2rem .45rem;border-radius:5px}}.good{{background:#dcfce7;color:#166534}}dl{{display:grid;grid-template-columns:8.6rem 1fr;gap:.55rem .8rem;margin:1rem 0}}dt{{font-weight:700;color:var(--deep)}}dd{{margin:0;color:#334155}}.action{{border-left:3px solid var(--brand);background:#effdf6;padding:.7rem .85rem;margin:1rem 0 0}}table{{width:100%;border-collapse:collapse;margin-top:1rem;font-size:.88rem}}th,td{{text-align:left;padding:.65rem;border-bottom:1px solid var(--line)}}td{{color:#087f51;text-align:center}}.muted{{color:var(--muted)}}.top{{border-left:4px solid var(--brand)}}@media(max-width:600px){{dl{{grid-template-columns:1fr}}dt{{margin-top:.35rem}}}}</style></head><body><main><header><div class="wordmark">{logo()}<span>Buildn</span></div><p class="kicker">DAILY INGEST DOSSIER · {DATE}</p><h1>{e(lane['title'])}</h1><p class="lead">{e(lane['readout'])}</p></header><section class="card"><h2>Signal map</h2>{signal(lane)}<p class="muted">Selection rationale: {e(lane['rationale'])}</p></section><section><h2>Dossier cards</h2>{cards}</section><section class="card"><h2>Use-case matrix</h2><table><thead><tr><th>Signal</th><th>Buildn OS</th><th>Client work</th><th>Agent workflow</th><th>Personal leverage</th></tr></thead><tbody>{matrix}</tbody></table><p class="muted">● direct fit &nbsp; ○ indirect / evaluate after a bounded test</p></section><section class="card top"><h2>Top actions</h2><ol>{''.join(f'<li>{e(s["usefulness"])}</li>' for s in lane['sources'])}</ol></section><section class="card"><h2>Source trail</h2><ul>{trail}</ul></section></main></body></html>'''

